var https = require('https');
var body = $input.first().json;
var image = body.image || '';
var mimeType = body.mimeType || 'image/jpeg';
var apiKey = process.env.ANTHROPIC_API_KEY || '';

var payload = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 600,
  messages: [{
    role: 'user',
    content: [
      { type: 'image', source: { type: 'base64', media_type: mimeType, data: image } },
      { type: 'text', text: 'Extract all contact information from this business card image. Return ONLY a valid JSON object with exactly these fields (use empty string if not present): name, company, title, email, phone, mobile, address, website. No explanation, no markdown, just the JSON.' }
    ]
  }]
};

var payloadStr = JSON.stringify(payload);

var result = await new Promise(function(resolve, reject) {
  var opts = {
    hostname: 'api.anthropic.com',
    path: '/v1/messages',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'Content-Length': Buffer.byteLength(payloadStr)
    }
  };
  var req = https.request(opts, function(res) {
    var chunks = [];
    res.on('data', function(c) { chunks.push(c); });
    res.on('end', function() {
      try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
      catch(e) { reject(new Error('Parse error: ' + e.message)); }
    });
  });
  req.on('error', reject);
  req.write(payloadStr);
  req.end();
});

var text = ((result.content || [{}])[0].text || '').trim();
text = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
var contact = {};
try { contact = JSON.parse(text); } catch(e) {}
return [{ json: contact }];
